  1	import * as React from 'react';
  2	import { DeleteObjectsCommandOutput } from '@aws-sdk/client-s3';
  3	import { pluralize } from '@odf/core/components/utils';
  4	import { FieldLevelHelp } from '@odf/shared';
  5	import { S3Commands } from '@odf/shared/s3';
  6	import { SelectableTable } from '@odf/shared/table';
  7	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  8	import { useModal } from '@openshift-console/dynamic-plugin-sdk';
  9	import { LaunchModal } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
 10	import { TFunction, Trans } from 'react-i18next';
 11	import {
 12	  useParams,
 13	  useSearchParams,
 14	  useNavigate,
 15	} from 'react-router-dom-v5-compat';
 16	import {
 17	  Button,
 18	  ButtonVariant,
 19	  Level,
 20	  LevelItem,
 21	  MenuToggle,
 22	  Alert,
 23	  AlertVariant,
 24	  AlertActionCloseButton,
 25	  AlertActionLink,
 26	  SearchInput,
 27	  Switch,
 28	} from '@patternfly/react-core';
 29	import {
 30	  ActionsColumn,
 31	  IAction,
 32	  CustomActionsToggleProps,
 33	} from '@patternfly/react-table';
 34	import { PREFIX, SEARCH } from '../../../constants';
 35	import {
 36	  ObjectsDeleteResponse,
 37	  SetObjectsDeleteResponse,
 38	} from '../../../modals/s3-browser/delete-objects/DeleteObjectsModal';
 39	import {
 40	  LazyDeleteObjectsModal,
 41	  LazyDeleteObjectsSummary,
 42	} from '../../../modals/s3-browser/delete-objects/LazyDeleteModals';
 43	import { ObjectCrFormat, S3ProviderType } from '../../../types';
 44	import { getNavigationURL } from '../../../utils';
 45	import { Pagination, PaginationProps } from '../pagination-helper';
 46	import { S3Context } from '../s3-context';
 47	import {
 48	  isRowSelectable,
 49	  getColumns,
 50	  TableRow,
 51	  EmptyPage,
 52	} from './table-components';
 53	import { useObjectsList } from './useObjectsList';
 54	
 55	const LazyCreateFolderModal = React.lazy(
 56	  () => import('../../../modals/s3-browser/create-folder/CreateFolderModal')
 57	);
 58	
 59	export type ExtraProps = {
 60	  setDeleteResponse: SetObjectsDeleteResponse;
 61	  refreshTokens: () => Promise<void>;
 62	  closeObjectSidebar: () => void;
 63	};
 64	
 65	type SearchObjectsProps = {
 66	  foldersPath: string;
 67	  bucketName: string;
 68	  providerType: S3ProviderType;
 69	  searchInput: string;
 70	  setSearchInput: React.Dispatch<React.SetStateAction<string>>;
 71	  className: string;
 72	};
 73	
 74	type TableActionsProps = {
 75	  launcher: LaunchModal;
 76	  selectedRows: ObjectCrFormat[];
 77	  loadedWOError: boolean;
 78	  foldersPath: string;
 79	  bucketName: string;
 80	  s3Client: S3Commands;
 81	  setDeleteResponse: SetObjectsDeleteResponse;
 82	  refreshTokens: () => Promise<void>;
 83	  searchInput: string;
 84	  setSearchInput: React.Dispatch<React.SetStateAction<string>>;
 85	  listAllVersions: boolean;
 86	  setListAllVersions: React.Dispatch<React.SetStateAction<boolean>>;
 87	  allowVersioning: boolean;
 88	};
 89	
 90	type DeletionAlertsProps = {
 91	  deleteResponse: ObjectsDeleteResponse;
 92	  foldersPath: string;
 93	};
 94	
 95	const getBulkActionsItems = (
 96	  t: TFunction,
 97	  launcher: LaunchModal,
 98	  selectedRows: ObjectCrFormat[],
 99	  foldersPath: string,
100	  bucketName: string,
101	  s3Client: S3Commands,
102	  setDeleteResponse: SetObjectsDeleteResponse,
103	  refreshTokens: () => Promise<void>,
104	  showVersioning: boolean,
105	  isVersioningEnabledOrSuspended: boolean
106	): IAction[] => [
107	  {
108	    title: showVersioning ? t('Delete versions') : t('Delete objects'),
109	    onClick: () =>
110	      launcher(LazyDeleteObjectsModal, {
111	        isOpen: true,
112	        extraProps: {
113	          foldersPath,
114	          bucketName,
115	          objects: selectedRows,
116	          s3Client,
117	          setDeleteResponse,
118	          refreshTokens,
119	          showVersioning,
120	          isVersioningEnabledOrSuspended,
121	        },
122	      }),
123	  },
124	];
125	
126	export const CustomActionsToggle = (props: CustomActionsToggleProps) => {
127	  const { t } = useCustomTranslation();
128	
129	  return (
130	    <MenuToggle
131	      ref={props.toggleRef}
132	      onClick={props.onToggle}
133	      isDisabled={props.isDisabled}
134	    >
135	      {t('Actions')}
136	    </MenuToggle>
137	  );
138	};
139	
140	const SearchObjects: React.FC<SearchObjectsProps> = ({
141	  foldersPath,
142	  bucketName,
143	  providerType,
144	  searchInput,
145	  setSearchInput,
146	  className,
147	}) => {
148	  const { t } = useCustomTranslation();
149	
150	  const navigate = useNavigate();
151	  const onClearURL = getNavigationURL(
152	    bucketName,
153	    providerType,
154	    foldersPath,
155	    ''
156	  );
157	
158	  return (
159	    <SearchInput
160	      placeholder={t('Search objects in the bucket using prefix')}
161	      value={searchInput}
162	      onChange={(_event, value) => {
163	        setSearchInput(value);
164	        if (value === '') navigate(onClearURL);
165	      }}
166	      onSearch={(_event, value) =>
167	        !!value &&
168	        navigate(getNavigationURL(bucketName, providerType, foldersPath, value))
169	      }
170	      onClear={() => {
171	        setSearchInput('');
172	        navigate(onClearURL);
173	      }}
174	      className={className}
175	    />
176	  );
177	};
178	
179	const TableActions: React.FC<PaginationProps & TableActionsProps> = ({
180	  onNext,
181	  onPrevious,
182	  loadedWOError,
183	  disableNext,
184	  disablePrevious,
185	  launcher,
186	  selectedRows,
187	  foldersPath,
188	  bucketName,
189	  s3Client,
190	  setDeleteResponse,
191	  refreshTokens,
192	  searchInput,
193	  setSearchInput,
194	  fromCount: paginationFromCount,
195	  toCount: paginationToCount,
196	  listAllVersions,
197	  setListAllVersions,
198	  allowVersioning,
199	}) => {
200	  const { t } = useCustomTranslation();
201	
202	  const versioningOnChange = (
203	    _event: React.FormEvent<HTMLInputElement>,
204	    checked: boolean
205	  ) => setListAllVersions(checked);
206	
207	  const anySelection = !!selectedRows.length;
208	  const providerType = s3Client.providerType as S3ProviderType;
209	
210	  return (
211	    <Level hasGutter>
212	      <LevelItem className="pf-v6-u-w-50">
213	        <div className="pf-v6-u-display-flex pf-v6-u-flex-direction-row">
214	          <SearchObjects
215	            foldersPath={foldersPath}
216	            bucketName={bucketName}
217	            providerType={providerType}
218	            searchInput={searchInput}
219	            setSearchInput={setSearchInput}
220	            className="pf-v6-u-mr-sm"
221	          />
222	          <Button
223	            variant={ButtonVariant.secondary}
224	            className="pf-v6-u-mr-sm"
225	            isDisabled={anySelection || !loadedWOError}
226	            onClick={() =>
227	              launcher(LazyCreateFolderModal, {
228	                isOpen: true,
229	                extraProps: { foldersPath, bucketName, s3Client },
230	              })
231	            }
232	          >
233	            {t('Create folder')}
234	          </Button>
235	          <ActionsColumn
236	            isDisabled={!anySelection || !loadedWOError}
237	            items={getBulkActionsItems(
238	              t,
239	              launcher,
240	              selectedRows,
241	              foldersPath,
242	              bucketName,
243	              s3Client,
244	              setDeleteResponse,
245	              refreshTokens,
246	              listAllVersions,
247	              allowVersioning
248	            )}
249	            actionsToggle={CustomActionsToggle}
250	            className="pf-v6-u-ml-sm"
251	          />
252	        </div>
253	      </LevelItem>
254	      {allowVersioning && (
255	        <LevelItem>
256	          <Switch
257	            id="list-versions-switch"
258	            label={t('List all versions')}
259	
260	            isChecked={listAllVersions}
261	            onChange={versioningOnChange}
262	          />
263	          <FieldLevelHelp>
264	            <Trans t={t}>
265	              <i>List all versions</i> allows you to view all object versions,
266	              including deleted objects that have delete markers. <br />
267	              Each version of an object is listed as a separate row, making it
268	              easier to track changes, restore previous versions, recover
269	              deleted data or permanently delete objects.
270	            </Trans>
271	          </FieldLevelHelp>
272	        </LevelItem>
273	      )}
274	      <LevelItem>
275	        <Pagination
276	          onNext={onNext}
277	          onPrevious={onPrevious}
278	          disableNext={disableNext}
279	          disablePrevious={disablePrevious}
280	          fromCount={paginationFromCount}
281	          toCount={paginationToCount}
282	        />
283	      </LevelItem>
284	    </Level>
285	  );
286	};
287	
288	export const DeletionAlerts: React.FC<DeletionAlertsProps> = ({
289	  deleteResponse,
290	  foldersPath,
291	}) => {
292	  const { t } = useCustomTranslation();
293	
294	  const launcher = useModal();
295	
296	  const [errorResponse, setErrorResponse] = React.useState<
297	    DeleteObjectsCommandOutput['Errors']
298	  >([]);
299	  const [successResponse, setSuccessResponse] = React.useState<
300	    DeleteObjectsCommandOutput['Deleted']
301	  >([]);
302	
303	  React.useEffect(() => {
304	    setErrorResponse(deleteResponse?.deleteResponse?.Errors || []);
305	    setSuccessResponse(deleteResponse?.deleteResponse?.Deleted || []);
306	  }, [deleteResponse]);
307	
308	  const errorCount = errorResponse.length;
309	  const successCount = successResponse.length;
310	  return (
311	    <>
312	      {!!errorCount && (
313	        <Alert
314	          variant={AlertVariant.danger}
315	          title={pluralize(
316	            errorCount,
317	            t(
318	              'Failed to delete {{ errorCount }} object from the bucket. View deletion summary for details.',
319	              { errorCount }
320	            ),
321	            t(
322	              'Failed to delete {{ errorCount }} objects from the bucket. View deletion summary for details.',
323	              { errorCount }
324	            ),
325	            false
326	          )}
327	          isInline
328	          className="pf-v6-u-mb-sm pf-v6-u-mt-lg"
329	          actionClose={
330	            <AlertActionCloseButton onClose={() => setErrorResponse([])} />
331	          }
332	          actionLinks={
333	            <AlertActionLink
334	              onClick={() =>
335	                launcher(LazyDeleteObjectsSummary, {
336	                  isOpen: true,
337	                  extraProps: {
338	                    foldersPath,
339	                    errorResponse,
340	                    selectedObjects: deleteResponse.selectedObjects,
341	                  },
342	                })
343	              }
344	            >
345	              {t('View failed objects')}
346	            </AlertActionLink>
347	          }
348	        />
349	      )}
350	      {!!successCount && (
351	        <Alert
352	          variant={AlertVariant.success}
353	          title={pluralize(
354	            successCount,
355	            t(
356	              'Successfully deleted {{ successCount }} object from the bucket.',
357	              { successCount }
358	            ),
359	            t(
360	              'Successfully deleted {{ successCount }} objects from the bucket.',
361	              { successCount }
362	            ),
363	            false
364	          )}
365	          isInline
366	          className="pf-v6-u-mb-lg pf-v6-u-mt-sm"
367	          actionClose={
368	            <AlertActionCloseButton onClose={() => setSuccessResponse([])} />
369	          }
370	        />
371	      )}
372	    </>
373	  );
374	};
375	
376	type ObjectsListProps = {
377	  onRowClick: (
378	    selectedObject: ObjectCrFormat,
379	    actionItems: React.MutableRefObject<IAction[]>,
380	    extraProps: ExtraProps
381	  ) => void;
382	  closeObjectSidebar: () => void;
383	  listAllVersions: boolean;
384	  setListAllVersions: React.Dispatch<React.SetStateAction<boolean>>;
385	  allowVersioning: boolean;
386	};
387	
388	export const ObjectsList: React.FC<ObjectsListProps> = ({
389	  onRowClick,
390	  closeObjectSidebar,
391	  listAllVersions,
392	  setListAllVersions,
393	  allowVersioning,
394	}) => {
395	  const { t } = useCustomTranslation();
396	
397	  const { bucketName } = useParams();
398	  const [searchParams] = useSearchParams();
399	
400	  const launcher = useModal();
401	
402	  // if non-empty means we are inside particular folder(s) of a bucket, else just inside a bucket (top-level)
403	  const foldersPath = searchParams.get(PREFIX) || '';
404	  // search objects within a bucket
405	  const searchQuery = searchParams.get(SEARCH) || '';
406	
407	  const { s3Client } = React.useContext(S3Context);
408	
409	  // used for multi-select bulk operations
410	  const [selectedRows, setSelectedRows] = React.useState<ObjectCrFormat[]>([]);
411	  // used for storing API's response on performing delete operation on objects
412	  const [deleteResponse, setDeleteResponse] =
413	    React.useState<ObjectsDeleteResponse>({
414	      selectedObjects: [] as ObjectCrFormat[],
415	      deleteResponse: {} as DeleteObjectsCommandOutput,
416	    });
417	  // used for storing input to the objects' search bar
418	  const [searchInput, setSearchInput] = React.useState(searchQuery);
419	  // used to store previous value of "foldersPath";
420	  const foldersPathPrevRef = React.useRef<string>();
421	
422	  const {
423	    error,
424	    isMutating,
425	    continuationTokens,
426	    structuredObjects,
427	    refreshTokens,
428	    paginationToCount,
429	    paginationFromCount,
430	    onNext,
431	    onPrevious,
432	  } = useObjectsList({
433	    bucketName,
434	    foldersPath,
435	    searchQuery,
436	    s3Client,
437	    setSelectedRows,
438	    listAllVersions,
439	  });
440	
441	  const loadedWOError = !isMutating && !error;
442	
443	  // initial fetch on first mount or on route update (drilling in/out of the folder view or searching objects using prefix)
444	  // or on "List all versions" toggle
445	  React.useEffect(() => {
446	    refreshTokens();
447	    if (foldersPathPrevRef.current !== foldersPath) {
448	      // only reset filter if navigated in/out of the current folder
449	      // not when search query is changed,
450	      // also, not when URL contains search query param
451	      if (!searchQuery) setSearchInput('');
452	      foldersPathPrevRef.current = foldersPath;
453	    }
454	    // eslint-disable-next-line react-hooks/exhaustive-deps
455	  }, [foldersPath, searchQuery, listAllVersions]);
456	
457	  return (
458	    <div className="pf-v6-u-m-lg">
459	      <p className="pf-v6-u-mb-sm">
460	        {t('Objects are the fundamental entities stored in buckets.')}
461	      </p>
462	      <DeletionAlerts
463	        deleteResponse={deleteResponse}
464	        foldersPath={foldersPath}
465	      />
466	      <TableActions
467	        onNext={onNext}
468	        onPrevious={onPrevious}
469	        selectedRows={selectedRows}
470	        loadedWOError={loadedWOError}
471	        disableNext={!continuationTokens.next || !loadedWOError}
472	        disablePrevious={!continuationTokens.current || !loadedWOError}
473	        launcher={launcher}
474	        foldersPath={foldersPath}
475	        bucketName={bucketName}
476	        s3Client={s3Client}
477	        setDeleteResponse={setDeleteResponse}
478	        refreshTokens={refreshTokens}
479	        searchInput={searchInput}
480	        setSearchInput={setSearchInput}
481	        fromCount={paginationFromCount}
482	        toCount={paginationToCount}
483	        listAllVersions={listAllVersions}
484	        setListAllVersions={setListAllVersions}
485	        allowVersioning={allowVersioning}
486	      />
487	      {listAllVersions && (
488	        <Alert
489	          isInline
490	          variant={AlertVariant.info}
491	          title={
492	            <Trans t={t}>
493	              <i>List all versions</i> is turned on. Each version is listed as a
494	              separate row, allowing you to track changes, restore previous
495	              versions, or permanently delete objects.
496	            </Trans>
497	          }
498	          className="pf-v6-u-mt-sm"
499	        />
500	      )}
501	      <SelectableTable
502	        key={listAllVersions ? 'versioned-list' : 'unversioned-list'}
503	        className="pf-v6-u-mt-lg"
504	        columns={getColumns(t, listAllVersions)}
505	        rows={structuredObjects}
506	        RowComponent={TableRow}
507	        selectedRows={selectedRows}
508	        setSelectedRows={setSelectedRows}
509	        loaded={!isMutating}
510	        loadError={error}
511	        isRowSelectable={isRowSelectable}
512	        extraProps={{
513	          launcher,
514	          bucketName,
515	          foldersPath,
516	          s3Client,
517	          setDeleteResponse,
518	          refreshTokens,
519	          onRowClick,
520	          closeObjectSidebar,
521	          showVersioning: listAllVersions,
522	          isVersioningEnabledOrSuspended: allowVersioning,
523	        }}
524	        emptyRowMessage={EmptyPage}
525	      />
526	    </div>
527	  );
528	};

